def splitIntoFibonacci(self, num: str) -> List[int]:
    n = len(num)
    result = []
    for i in range(n):
        if num[i] == '0':
            continue
        if i == 0 or i == 1:
            result.append(int(num[i]))
        elif num[i - 1] == '0':
            continue
        elif num[i - 1] == num[i]:
            result.append(int(num[i - 1]) + int(num[i]))
        else:
            result.append(int(num[i - 1]) + int(num[i]) + int(num[i + 1]))
    return result

